   410 | // the offset fails.
   411 | static OffsetResult collectOffsets(GEPOperator &GEP, const DataLayout &DL) {
   412 |   OffsetResult Result(GEP, DL);
   413 |   unsigned BitWidth = Result.ConstantOffset.getBitWidth();
